import { Component, OnInit, OnDestroy } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { ApiService } from '../../services/api.service';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-booking',
  templateUrl: './booking.component.html'
})
export class BookingComponent implements OnInit, OnDestroy {
  public bus: any = null;
  public busStops: any = { boarding: [], dropping: [] };
  public selectedSeats: string[] = [];
  public reservationToken = '';
  public lockExpiry = '';
  public lockExpiryDate: Date | null = null;
  public message = '';
  public isSuccess = false;
  public isLoading = true;
  public passengers: any[] = [];
  public paymentMethod = 'card';
  public bookingConfirmed = false;
  public confirmedRef = '';

  // step: 1=seats, 2=stops, 3=passengers+payment
  public step = 1;
  public selectedPickup = '';
  public selectedDropping = '';

  private timerInterval: any;
  public secondsLeft = 0;

  constructor(
    private route: ActivatedRoute,
    private api: ApiService,
    public auth: AuthService,
    private router: Router
  ) {}

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id') || '';
    if (!id) {
      this.router.navigate(['/search']);
      return;
    }

    this.api.getBus(id).subscribe({
      next: (result: any) => {
        this.bus = result;
        this.isLoading = false;
        this.api.getBusStops(id).subscribe({
          next: (stops: any) => this.busStops = stops,
          error: () => {}
        });
      },
      error: () => {
        this.isLoading = false;
        this.router.navigate(['/search']);
      }
    });
  }

  ngOnDestroy(): void {
    if (this.timerInterval) clearInterval(this.timerInterval);
  }

  public getSeatRows(): any[][] {
    if (!this.bus?.allSeats) return [];
    const seats = this.bus.allSeats as any[];
    const rowMap: { [key: string]: any[] } = {};
    for (const seat of seats) {
      const match = seat.seatCode.match(/^(\d+)([A-D])$/);
      if (match) {
        const row = match[1];
        if (!rowMap[row]) rowMap[row] = [null, null, null, null];
        const colIndex = 'ABCD'.indexOf(match[2]);
        rowMap[row][colIndex] = seat;
      }
    }
    return Object.keys(rowMap).sort((a, b) => +a - +b).map(r => rowMap[r]);
  }

  public getSeatState(seat: any): string {
    if (!seat) return 'empty';
    if (this.selectedSeats.includes(seat.seatCode)) return 'selected';
    if (!seat.isAvailable) return 'unavailable';
    if (seat.isLocked) return 'locked';
    return 'available';
  }

  public toggleSeat(seat: any) {
    if (!seat || !seat.isAvailable || seat.isLocked) return;
    const code = seat.seatCode;
    if (this.selectedSeats.includes(code)) {
      this.selectedSeats = this.selectedSeats.filter(s => s !== code);
    } else {
      this.selectedSeats.push(code);
    }
    this.syncPassengers();
  }

  private syncPassengers() {
    while (this.passengers.length < this.selectedSeats.length) {
      this.passengers.push({ name: '', email: '', phoneNumber: '', age: 18, seatNumber: '' });
    }
    while (this.passengers.length > this.selectedSeats.length) {
      this.passengers.pop();
    }
    this.passengers = this.passengers.map((p, i) => ({ ...p, seatNumber: this.selectedSeats[i] || '' }));
  }

  public lockSeats() {
    this.message = '';
    if (this.selectedSeats.length === 0) {
      this.message = 'Please select at least one seat.';
      return;
    }
    const payload = {
      busId: this.bus.id,
      seatCodes: this.selectedSeats,
      reservationToken: this.reservationToken || undefined
    };
    this.api.selectSeats(payload).subscribe({
      next: (result: any) => {
        this.reservationToken = result.reservationToken;
        this.lockExpiryDate = new Date(result.lockedUntil);
        this.lockExpiry = this.lockExpiryDate.toLocaleTimeString();
        this.startTimer();
        this.message = '';
        this.step = 2;
      },
      error: err => {
        this.message = err.error?.message || err.error || err.statusText || 'Failed to reserve seats.';
      }
    });
  }

  private startTimer() {
    if (this.timerInterval) clearInterval(this.timerInterval);
    this.timerInterval = setInterval(() => {
      if (!this.lockExpiryDate) return;
      this.secondsLeft = Math.max(0, Math.floor((this.lockExpiryDate.getTime() - Date.now()) / 1000));
      if (this.secondsLeft === 0) {
        clearInterval(this.timerInterval);
        this.reservationToken = '';
        this.message = 'Seat reservation expired. Please select seats again.';
      }
    }, 1000);
  }

  public get timerDisplay(): string {
    const m = Math.floor(this.secondsLeft / 60).toString().padStart(2, '0');
    const s = (this.secondsLeft % 60).toString().padStart(2, '0');
    return `${m}:${s}`;
  }

  public confirmStops(): void {
    const hasStops = this.busStops.boarding.length > 0 || this.busStops.dropping.length > 0;
    if (hasStops) {
      if (this.busStops.boarding.length > 0 && !this.selectedPickup) {
        this.message = 'Please select a boarding stop.';
        return;
      }
      if (this.busStops.dropping.length > 0 && !this.selectedDropping) {
        this.message = 'Please select a dropping stop.';
        return;
      }
    }
    this.message = '';
    this.step = 3;
  }

  public isPassengersValid(): boolean {
    return this.passengers.every(p => p.name && p.email && p.phoneNumber && p.age > 0);
  }

  public confirmBooking() {
    if (!this.auth.isAuthenticated()) {
      this.router.navigate(['/auth'], { queryParams: { returnUrl: this.router.url } });
      return;
    }

    if (!this.reservationToken) {
      this.message = 'Please reserve seats first.';
      return;
    }

    if (!this.isPassengersValid()) {
      this.message = 'Please fill in all passenger details.';
      return;
    }

    const payload = {
      busId: this.bus.id,
      reservationToken: this.reservationToken,
      paymentMethod: this.paymentMethod,
      passengerDetails: this.passengers,
      pickupStop: this.selectedPickup || null,
      droppingStop: this.selectedDropping || null
    };

    this.api.confirmBooking(payload).subscribe({
      next: (result: any) => {
        this.bookingConfirmed = true;
        this.confirmedRef = result.reference;
        this.isSuccess = true;
        this.message = '';
        if (this.timerInterval) clearInterval(this.timerInterval);
      },
      error: err => {
        const errMsg = err.error?.message || err.error || err.statusText || 'Booking failed.';
        this.message = errMsg;
        this.isSuccess = false;
      }
    });
  }

  public goToDashboard() {
    this.router.navigate(['/dashboard']);
  }
}
<div *ngIf="isLoading" class="card" style="text-align:center;padding:40px">
  <div class="spinner"></div>
  <p>Loading bus details…</p>
</div>

<!-- Booking confirmed screen -->
<div *ngIf="bookingConfirmed" class="card booking-success">
  <div class="success-icon">✓</div>
  <h2>Booking Confirmed!</h2>
  <p>Your booking reference is:</p>
  <div class="booking-ref">{{ confirmedRef }}</div>
  <p style="color:#666;margin-top:8px">A confirmation email has been sent to your inbox.</p>
  <button class="btn btn-primary" style="margin-top:20px" (click)="goToDashboard()">View My Bookings</button>
</div>

<div *ngIf="!isLoading && bus && !bookingConfirmed" class="booking-page">

  <!-- Bus Info Header -->
  <div class="card bus-header">
    <div class="bus-title">
      <h2>{{ bus.busName || bus.registrationNumber }}</h2>
      <span class="bus-type-badge" *ngIf="bus.busType">{{ bus.busType }}</span>
    </div>
    <div class="bus-meta">
      <div class="meta-item">
        <span class="meta-label">From</span>
        <span class="meta-value">{{ bus.route?.source }}</span>
      </div>
      <div class="meta-arrow">→</div>
      <div class="meta-item">
        <span class="meta-label">To</span>
        <span class="meta-value">{{ bus.route?.destination }}</span>
      </div>
      <div class="meta-divider"></div>
      <div class="meta-item">
        <span class="meta-label">Date</span>
        <span class="meta-value">{{ bus.travelDate | date:'EEE, MMM d, y' }}</span>
      </div>
      <div class="meta-item">
        <span class="meta-label">Departure</span>
        <span class="meta-value dep-time">{{ bus.departureTime }}</span>
      </div>
      <div *ngIf="bus.arrivalTime" class="meta-item">
        <span class="meta-label">Arrival</span>
        <span class="meta-value">{{ bus.arrivalTime }}</span>
      </div>
      <div class="meta-item">
        <span class="meta-label">Price/Seat</span>
        <span class="meta-value price-val">₹{{ bus.price }}</span>
      </div>
    </div>
    <p class="seat-avail-info">
      <strong>{{ bus.availableSeats }}</strong> of <strong>{{ bus.totalSeats }}</strong> seats available
    </p>
  </div>

  <!-- Step indicator -->
  <div class="step-bar card" style="display:flex;gap:0;padding:0;overflow:hidden;margin-bottom:0">
    <div class="step-item" [class.step-active]="step===1" [class.step-done]="step>1">
      <span class="step-num">1</span><span class="step-label">Select Seats</span>
    </div>
    <div class="step-item" [class.step-active]="step===2" [class.step-done]="step>2">
      <span class="step-num">2</span><span class="step-label">Pick Stops</span>
    </div>
    <div class="step-item" [class.step-active]="step===3">
      <span class="step-num">3</span><span class="step-label">Passenger &amp; Pay</span>
    </div>
  </div>

  <!-- Timer (visible on steps 2 and 3) -->
  <div class="timer-bar" *ngIf="reservationToken && step > 1" [class.timer-urgent]="secondsLeft < 60">
    <span>Seats {{ selectedSeats.join(', ') }} reserved — complete payment in <strong>{{ timerDisplay }}</strong></span>
  </div>

  <!-- STEP 1: Seat Selection -->
  <div class="card" *ngIf="step === 1">
    <h3 class="section-title">Select Your Seats</h3>
    <div class="seat-legend">
      <div class="legend-item"><span class="seat-btn available">1A</span><span>Available</span></div>
      <div class="legend-item"><span class="seat-btn selected">1B</span><span>Selected</span></div>
      <div class="legend-item"><span class="seat-btn locked">1C</span><span>Locked</span></div>
      <div class="legend-item"><span class="seat-btn unavailable">1D</span><span>Booked</span></div>
    </div>
    <div class="bus-layout">
      <div class="bus-front"><div class="driver-seat">🚌 Driver</div></div>
      <div class="seat-matrix">
        <div class="seat-matrix-header">
          <span class="col-label">Window</span><span class="col-label">Aisle</span>
          <span class="aisle-gap"></span>
          <span class="col-label">Aisle</span><span class="col-label">Window</span>
        </div>
        <div class="seat-row" *ngFor="let row of getSeatRows(); index as rowIndex">
          <span class="row-number">{{ rowIndex + 1 }}</span>
          <ng-container *ngFor="let seat of row; index as colIndex">
            <span *ngIf="colIndex === 2" class="aisle-gap"></span>
            <button *ngIf="seat" class="seat-btn" [ngClass]="getSeatState(seat)"
              [title]="seat.seatCode" [disabled]="!seat.isAvailable || seat.isLocked"
              (click)="toggleSeat(seat)">{{ seat.seatCode }}</button>
            <span *ngIf="!seat" class="seat-empty"></span>
          </ng-container>
        </div>
      </div>
    </div>
    <div *ngIf="selectedSeats.length > 0" class="selected-summary">
      <p>Selected: <strong>{{ selectedSeats.join(', ') }}</strong></p>
      <p>Total: <strong class="price-total">₹{{ selectedSeats.length * bus.price }}</strong></p>
      <button class="btn btn-primary" (click)="lockSeats()">
        Reserve {{ selectedSeats.length }} Seat{{ selectedSeats.length > 1 ? 's' : '' }} — Continue
      </button>
    </div>
    <button *ngIf="selectedSeats.length === 0" class="btn btn-primary" disabled>Select seats to continue</button>
  </div>

  <!-- STEP 2: Stop Picker -->
  <div class="card" *ngIf="step === 2">
    <h3 class="section-title">Choose Your Boarding &amp; Dropping Stops</h3>
    <p style="color:#64748b;font-size:0.9rem;margin-bottom:16px">
      {{ bus.route?.source }} → {{ bus.route?.destination }}
    </p>

    <div class="stop-picker">
      <!-- Boarding -->
      <div class="stop-picker-col">
        <h4 style="color:#16a34a">Boarding Stop
          <small style="color:#64748b;font-weight:400"> ({{ bus.route?.source }})</small>
        </h4>
        <div *ngIf="busStops.boarding.length === 0" style="color:#64748b;font-size:0.9rem">
          No specific stops — boarding at {{ bus.boardingPoint || bus.route?.source }}.
        </div>
        <label *ngFor="let s of busStops.boarding" class="stop-option"
          [class.selected]="selectedPickup === s.stopName" (click)="selectedPickup = s.stopName">
          <input type="radio" [value]="s.stopName" [(ngModel)]="selectedPickup" name="pickup" />
          {{ s.stopName }}
        </label>
      </div>

      <!-- Dropping -->
      <div class="stop-picker-col">
        <h4 style="color:#dc2626">Dropping Stop
          <small style="color:#64748b;font-weight:400"> ({{ bus.route?.destination }})</small>
        </h4>
        <div *ngIf="busStops.dropping.length === 0" style="color:#64748b;font-size:0.9rem">
          No specific stops — dropping at {{ bus.droppingPoint || bus.route?.destination }}.
        </div>
        <label *ngFor="let s of busStops.dropping" class="stop-option"
          [class.selected]="selectedDropping === s.stopName" (click)="selectedDropping = s.stopName">
          <input type="radio" [value]="s.stopName" [(ngModel)]="selectedDropping" name="dropping" />
          {{ s.stopName }}
        </label>
      </div>
    </div>

    <div *ngIf="message" class="alert alert-error" style="margin-bottom:12px">{{ message }}</div>
    <button class="btn btn-primary btn-large" (click)="confirmStops()">Continue to Passenger Details</button>
    <button class="btn" style="margin-left:12px" (click)="step=1; message=''">Back</button>
  </div>

  <!-- STEP 3: Passenger Details + Payment -->
  <div class="card" *ngIf="step === 3">
    <!-- Stops summary -->
    <div class="selected-stops-summary" *ngIf="selectedPickup || selectedDropping"
      style="background:var(--bg);border-radius:8px;padding:10px 14px;margin-bottom:16px;font-size:0.9rem;display:flex;gap:24px">
      <span *ngIf="selectedPickup">Boarding: <strong>{{ selectedPickup }}</strong></span>
      <span *ngIf="selectedDropping">Dropping: <strong>{{ selectedDropping }}</strong></span>
    </div>

    <h3 class="section-title">Passenger Details</h3>
    <div *ngFor="let passenger of passengers; index as i" class="passenger-card">
      <div class="passenger-header">
        <span>Passenger {{ i + 1 }}</span>
        <span class="seat-badge">Seat {{ passenger.seatNumber }}</span>
      </div>
      <div class="form-grid">
        <div class="form-group">
          <label>Full Name *</label>
          <input [(ngModel)]="passenger.name" name="name{{i}}" required placeholder="As on ID proof" />
        </div>
        <div class="form-group">
          <label>Age *</label>
          <input type="number" [(ngModel)]="passenger.age" name="age{{i}}" min="1" max="120" required />
        </div>
        <div class="form-group">
          <label>Email *</label>
          <input type="email" [(ngModel)]="passenger.email" name="email{{i}}" required placeholder="For ticket confirmation" />
        </div>
        <div class="form-group">
          <label>Phone *</label>
          <input [(ngModel)]="passenger.phoneNumber" name="phone{{i}}" required placeholder="10-digit mobile number" />
        </div>
      </div>
    </div>

    <div class="payment-section">
      <h3 class="section-title">Payment</h3>
      <div class="payment-methods">
        <label class="payment-option" [class.active]="paymentMethod === 'card'">
          <input type="radio" [(ngModel)]="paymentMethod" value="card" name="pm" />
          <span>💳 Debit / Credit Card</span>
        </label>
        <label class="payment-option" [class.active]="paymentMethod === 'upi'">
          <input type="radio" [(ngModel)]="paymentMethod" value="upi" name="pm" />
          <span>📱 UPI</span>
        </label>
        <label class="payment-option" [class.active]="paymentMethod === 'netbanking'">
          <input type="radio" [(ngModel)]="paymentMethod" value="netbanking" name="pm" />
          <span>🏦 Net Banking</span>
        </label>
        <label class="payment-option test-mode" [class.active]="paymentMethod === 'timeout'">
          <input type="radio" [(ngModel)]="paymentMethod" value="timeout" name="pm" />
          <span>⚠ Simulate Timeout (test)</span>
        </label>
      </div>
      <div class="fare-summary">
        <div class="fare-row">
          <span>Base fare × {{ passengers.length }} passenger{{ passengers.length > 1 ? 's' : '' }}</span>
          <span>₹{{ selectedSeats.length * bus.price }}</span>
        </div>
        <div class="fare-row total-row">
          <span><strong>Total Amount</strong></span>
          <span><strong class="price-total">₹{{ selectedSeats.length * bus.price }}</strong></span>
        </div>
      </div>
      <div *ngIf="!auth.isAuthenticated()" class="login-notice">
        ⚠ You need to <a routerLink="/auth">log in or sign up</a> to complete your booking.
      </div>
      <div style="display:flex;gap:12px;align-items:center;flex-wrap:wrap">
        <button class="btn btn-success btn-large" (click)="confirmBooking()" [disabled]="!isPassengersValid()">
          Confirm &amp; Pay ₹{{ selectedSeats.length * bus.price }}
        </button>
        <button class="btn" (click)="step=2; message=''">Back to Stops</button>
      </div>
    </div>
  </div>

  <!-- Alert Messages -->
  <div *ngIf="message && step !== 2" class="alert" [class.alert-error]="!isSuccess" [class.alert-success]="isSuccess">
    {{ message }}
  </div>
</div>
